#include<bits/stdc++.h>
#define rep(a,b,c) for(int c=(a);c<=(b);++c)
using namespace std;
inline int read()
{
	int res=0;char ch=getchar();bool flag=0;
	while(ch<'0'||ch>'9')flag^=(ch=='-'),ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();
	return flag ? -res : res ; 
}
const int N=8e4+10;int a[N],b[N],T1,T2,T3,T4;
struct FHQ{int l,r,siz,val,key,f;}t[N];int cnt,stk[N],top,Rt;
inline int Node(int k){t[++cnt].siz=1;t[cnt].key=rand();t[cnt].val=k;return cnt;}
inline void update(int k){t[k].siz=t[t[k].l].siz+t[t[k].r].siz+1;t[t[k].l].f=t[t[k].r].f=k;t[k].f=t[0].f=0;}
void split(int cur,int pos,int &x,int &y)
{
	if(!cur){x=y=0;return;}
	if(t[t[cur].l].siz>=pos)y=cur,split(t[cur].l,pos,x,t[cur].l),update(cur);
	else x=cur,split(t[cur].r,pos-t[t[cur].l].siz-1,t[cur].r,y),update(cur);
}
int merge(int x,int y)
{
	if(!x||!y)return x|y;
	if(t[x].key<t[y].key){t[x].r=merge(t[x].r,y);update(x);return x;}
	t[y].l=merge(x,t[y].l);update(y);return y;
}
inline int Rnk(int k)
{
	int cur=a[k],res=t[t[a[k]].l].siz+1;
	while(t[cur].f)res+=(cur==t[t[cur].f].r)*(t[t[t[cur].f].l].siz+1),cur=t[cur].f;return res;
}
int Fnd(int cur,int pos)
{
	if(t[t[cur].l].siz==pos)return cur;
	if(t[t[cur].l].siz>pos)return Fnd(t[cur].l,pos);
	else return Fnd(t[cur].r,pos-t[t[cur].l].siz-1);
}
int main()
{
	int n=read(),m=read();rep(1,n,i){int x=read();Rt=merge(Rt,Node(x));a[x]=i;b[i]=x;}
	rep(1,m,i)
	{
		char opt[10];int x,y;scanf("%s",opt);
		switch(opt[0])
		{
			case 'T':
				x=read();split(Rt,Rnk(x)-1,T1,T2);
				split(T2,1,T2,T3);Rt=merge(merge(T2,T1),T3);break;
			case 'B':
				x=read();split(Rt,Rnk(x)-1,T1,T2);
				split(T2,1,T2,T3);Rt=merge(merge(T1,T3),T2);break;
				
			case 'I':
				x=read();y=read();if(!y)break;if(y==1)
				{
					split(Rt,Rnk(x)-1,T1,T2);
					split(T2,1,T2,T3);split(T3,1,T3,T4);
					Rt=merge(merge(merge(T1,T3),T2),T4);break;
				}
				split(Rt,Rnk(x)-2,T1,T2);
				split(T2,1,T2,T3);split(T3,1,T3,T4);
				Rt=merge(merge(merge(T1,T3),T2),T4);break;
			case 'A': printf("%d\n",Rnk(read())-1);break;
			case 'Q': printf("%d\n",b[Fnd(Rt,read()-1)]);break;
		}
	}
}
